<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Visualizer</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #0d1117;
    color: #c9d1d9;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 24px 16px;
  }
  h1 {
    font-size: 18px;
    font-weight: 500;
    margin-bottom: 16px;
    color: #e6edf3;
    letter-spacing: 0.3px;
  }
  .controls {
    display: flex;
    gap: 8px;
    margin-bottom: 20px;
  }
  button {
    background: #21262d;
    color: #c9d1d9;
    border: 1px solid #30363d;
    padding: 8px 18px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 14px;
    font-weight: 500;
    transition: background 0.15s, border-color 0.15s, transform 0.05s;
  }
  button:hover { background: #30363d; border-color: #484f58; }
  button:active { background: #1c2128; transform: translateY(1px); }
  button:disabled { opacity: 0.5; cursor: not-allowed; }

  #bars {
    display: flex;
    align-items: flex-end;
    justify-content: center;
    gap: 2px;
    height: 420px;
    width: 100%;
    max-width: 1200px;
    background: #161b22;
    border: 1px solid #30363d;
    border-radius: 8px;
    padding: 12px;
  }
  .bar {
    flex: 1 1 0;
    background: linear-gradient(to top, #388bfd, #58a6ff);
    min-width: 3px;
    border-radius: 2px 2px 0 0;
    transition: height 0.06s ease, background 0.1s;
  }
  .bar.compare {
    background: linear-gradient(to top, #d29922, #f0c674);
  }
  .bar.swap {
    background: linear-gradient(to top, #da3633, #f85149);
  }
  .bar.sorted {
    background: linear-gradient(to top, #238636, #3fb950);
  }
  .info {
    margin-top: 14px;
    font-size: 12px;
    color: #8b949e;
    text-align: center;
  }
  .stats {
    margin-top: 8px;
    font-size: 12px;
    color: #6e7681;
    font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  }
</style>
</head>
<body>
  <h1>Sorting Algorithm Visualizer</h1>
  <div class="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
  </div>
  <div id="bars"></div>
  <div class="info">Click <b>Sort</b> to animate. <b>Shuffle</b> generates a new random array. <b>Reset</b> restores the original.</div>
  <div class="stats" id="stats">comparisons: 0 &nbsp;|&nbsp; swaps: 0</div>

<script>
(function () {
  "use strict";

  const SIZE = 60;
  const MAX_VAL = 100;
  const ANIM_DELAY = 18; // ms per step during animation

  let originalArray = [];
  let animating = false;
  let animTimer = null;
  let comparisons = 0;
  let swaps = 0;

  // Insertion-sort step state.
  const state = {
    arr: [],
    i: 1,     // outer index (the element being inserted)
    j: 0,     // inner index (compares arr[j] with arr[j+1])
    done: false,
  };

  // ---------- helpers ----------
  function randomArray(n) {
    const a = new Array(n);
    for (let i = 0; i < n; i++) {
      a[i] = Math.floor(Math.random() * MAX_VAL) + 1;
    }
    return a;
  }

  function $bars() {
    return document.querySelectorAll("#bars .bar");
  }

  function render() {
    const container = document.getElementById("bars");
    container.innerHTML = "";
    const frag = document.createDocumentFragment();
    for (let k = 0; k < state.arr.length; k++) {
      const bar = document.createElement("div");
      bar.className = "bar";
      bar.style.height = (state.arr[k] / MAX_VAL * 100) + "%";
      frag.appendChild(bar);
    }
    container.appendChild(frag);
    updateStats();
  }

  function syncHeights() {
    const els = $bars();
    for (let k = 0; k < state.arr.length && k < els.length; k++) {
      els[k].style.height = (state.arr[k] / MAX_VAL * 100) + "%";
    }
  }

  function clearHighlights() {
    const els = $bars();
    for (let k = 0; k < els.length; k++) {
      els[k].classList.remove("compare", "swap");
    }
  }

  function addHighlight(indices, cls) {
    const els = $bars();
    for (let i = 0; i < indices.length; i++) {
      const el = els[indices[i]];
      if (el) el.classList.add(cls);
    }
  }

  function markAllSorted() {
    const els = $bars();
    for (let k = 0; k < els.length; k++) {
      els[k].classList.remove("compare", "swap");
      els[k].classList.add("sorted");
    }
  }

  function updateStats() {
    document.getElementById("stats").textContent =
      "comparisons: " + comparisons + "  |  swaps: " + swaps;
  }

  // ---------- sort API ----------
  function isSorted() {
    const a = state.arr;
    for (let k = 1; k < a.length; k++) {
      if (a[k - 1] > a[k]) return false;
    }
    return true;
  }

  /**
   * Performs exactly one comparison/step of insertion sort.
   * Returns true once the array is fully sorted.
   */
  function sortStep() {
    if (state.done) return true;

    clearHighlights();

    // If we've finished the outer pass, we're done.
    if (state.i >= state.arr.length) {
      state.done = true;
      markAllSorted();
      return true;
    }

    // j < 0 means the current element has "bubbled" all the way down;
    // advance to the next outer index.
    if (state.j < 0) {
      state.i++;
      state.j = state.i - 1;
      if (state.i >= state.arr.length) {
        state.done = true;
        markAllSorted();
        return true;
      }
      return false;
    }

    // One comparison: arr[j] vs arr[j+1].
    comparisons++;
    addHighlight([state.j, state.j + 1], "compare");
    if (state.arr[state.j] > state.arr[state.j + 1]) {
      const tmp = state.arr[state.j];
      state.arr[state.j] = state.arr[state.j + 1];
      state.arr[state.j + 1] = tmp;
      swaps++;
      syncHeights();
      addHighlight([state.j, state.j + 1], "swap");
      updateStats();
    }
    state.j--;
    return false;
  }

  function resetSortState() {
    state.i = 1;
    state.j = 0;
    state.done = false;
    comparisons = 0;
    swaps = 0;
    updateStats();
  }

  // ---------- animation control ----------
  function stopAnimation() {
    if (animTimer != null) {
      clearTimeout(animTimer);
      animTimer = null;
    }
    animating = false;
  }

  function animateTick() {
    if (state.done) {
      stopAnimation();
      return;
    }
    sortStep();
    animTimer = setTimeout(animateTick, ANIM_DELAY);
  }

  function startAnimation() {
    if (state.done || animating) return;
    animating = true;
    animTimer = setTimeout(animateTick, ANIM_DELAY);
  }

  function shuffle() {
    stopAnimation();
    state.arr = randomArray(SIZE);
    originalArray = state.arr.slice();
    resetSortState();
    render();
  }

  function reset() {
    stopAnimation();
    state.arr = originalArray.slice();
    resetSortState();
    render();
  }

  // ---------- wire up buttons ----------
  document.getElementById("sort").addEventListener("click", startAnimation);
  document.getElementById("shuffle").addEventListener("click", shuffle);
  document.getElementById("reset").addEventListener("click", reset);

  // ---------- init ----------
  state.arr = randomArray(SIZE);
  originalArray = state.arr.slice();
  render();

  // ---------- public API for grading ----------
  window.viz = {
    array: function () { return state.arr.slice(); },
    setArray: function (a) {
      stopAnimation();
      const src = Array.isArray(a) ? a : [];
      const next = new Array(src.length);
      for (let k = 0; k < src.length; k++) {
        const n = Number(src[k]);
        next[k] = isFinite(n) ? n : 0;
      }
      state.arr = next;
      originalArray = next.slice();
      resetSortState();
      render();
    },
    sortStep: sortStep,
    sorted: isSorted,
  };
})();
</script>
</body>
</html>
